import ldap3
from ldap3 import Server, Connection, ALL

def search_ldap_user(username):
    server = Server('<LDAP_SERVER>', get_info=ALL)
    conn = Connection(server, user='<ADMIN_DN>', password='<ADMIN_PASSWORD>')
    
    if not conn.bind():
        print("Cannot connect to the server.")
        return None
        
    search_base = 'dc=example,dc=com' # Replace with your actual LDAP base DN 
    search_filter = f'(sAMAccountName={username})'
    
    if not conn.search(search_base=search_base, search_filter=search_filter):
        print("Cannot perform the search.")
